    public sealed class WriteResult
    {
        public int WrittenCount { get; set; }
        public int RejectedCount { get; set; }
        public List<TypeViolation> Violations { get; private set; } = new List<TypeViolation>();

        // ── Serialization ──

        public byte[] ToByteArray()
        {
            var w = new ProtoWriter();
            if (WrittenCount != 0) w.WriteInt32(1, WrittenCount);
            if (RejectedCount != 0) w.WriteInt32(2, RejectedCount);
            foreach (var item in Violations)
                w.WriteMessageBytes(3, item.ToByteArray());
            return w.ToArray();
        }

        // ── Deserialization ──

        public static readonly MessageParser<WriteResult> Parser = new MessageParser<WriteResult>(data => ParseFrom(data));

        public static WriteResult ParseFrom(byte[] data)
        {
            if (data == null || data.Length == 0) return new WriteResult();
            var r = new ProtoReader(data);
            var msg = new WriteResult();
            int field; ProtoWireType wire;
            while (r.TryReadTag(out field, out wire))
            {
                switch (field)
                {
                    case 1: msg.WrittenCount = r.ReadInt32(); break;
                    case 2: msg.RejectedCount = r.ReadInt32(); break;
                    case 3: msg.Violations.Add(TypeViolation.ParseFrom(r.ReadLengthDelimited())); break;
                    default: r.SkipField(wire); break;
                }
            }
            return msg;
        }
    }

